GameState.state.units["TST_TRUKK"] = {"id":"TST_TRUKK","owner":2,"status":2,"flags":{},"transport_data":{"capacity":12,"embarked_units":["TST_BOYZ"]},"meta":{"name":"Test Transport","keywords":["VEHICLE","TRANSPORT"],"stats":{"move":12}},"models":[{"id":"t0","alive":true,"wounds":10,"current_wounds":10,"base_mm":100,"base_type":"circular","position":{"x":1600,"y":700},"rotation":0.0}]}
GameState.state.units["TST_BOYZ"] = {"id":"TST_BOYZ","owner":2,"status":2,"embarked_in":"TST_TRUKK","flags":{},"meta":{"name":"Test Squad","keywords":["INFANTRY"],"stats":{"move":6}},"models":[{"id":"b0","alive":true,"wounds":1,"current_wounds":1,"base_mm":32,"base_type":"circular","position":null},{"id":"b1","alive":true,"wounds":1,"current_wounds":1,"base_mm":32,"base_type":"circular","position":null},{"id":"b2","alive":true,"wounds":1,"current_wounds":1,"base_mm":32,"base_type":"circular","position":null}]}
PhaseManager.get_current_phase_instance().game_state_snapshot = GameState.state.duplicate(true)
var main = tree.current_scene
if main.has_method("_recreate_unit_visuals"):
	main._recreate_unit_visuals()
var mc = main.movement_controller
if mc and mc.has_method("_refresh_unit_list"):
	mc._refresh_unit_list()
return GameState.state.units.has("TST_BOYZ")

var mc = tree.current_scene.movement_controller
var ul = mc.unit_list
var idx = -1
for i in range(ul.get_item_count()):
	if ul.get_item_metadata(i) == "TST_BOYZ":
		idx = i
		break
if idx < 0:
	var labels = []
	for i in range(ul.get_item_count()):
		labels.append(str(ul.get_item_metadata(i)))
	return "not_in_list:" + str(labels)
ul.select(idx)
ul.emit_signal("item_selected", idx)
return "selected"

var d = node.get_node_or_null("DisembarkDialog")
if d == null:
	return false
var txt = str(d.dialog_text)
return ("has not moved" in txt) and (not d.get_ok_button().disabled)

var d = node.get_node_or_null("DisembarkDialog")
if d == null:
	return false
d.get_ok_button().emit_signal("pressed")
return true

var ctrls = tree.get_nodes_in_group("disembark_controllers")
if ctrls.size() == 0:
	return false
var c = ctrls[0]
return c.unit_id == "TST_BOYZ" and c.disembark_mode == "tactical" and c.setup_range_inches == 3.0
